import { client } from "@/utils/helper";
import { cookies } from "next/headers";

const getMe = async () => {

   const cookieStore = await cookies();

   const token =
      cookieStore.get("jwt")?.value;

   if (!token) {
      return { user: null };
   }

   const response = await client.get(
      "user/get",
      {
         headers: {
            Authorization: token
         }
      }
   );

   return response.data;
};

export {
   getMe
};